def mock_navigator_geolocation(success_callback, error_callback):
    # Simulate user clicking "Allow"
    user_allowed = True

    if user_allowed:
        # Mock GPS data
        position = {'coords': {'latitude': 37.7749, 'longitude': -122.4194}}
        success_callback(position)
    else:
        error_callback("User denied Geolocation")

def on_success(pos):
    lat = pos['coords']['latitude']
    lon = pos['coords']['longitude']
    print(f"Success! You are at {lat}, {lon}")

def on_error(err):
    print(f"Error: {err}")

# Call the API
mock_navigator_geolocation(on_success, on_error)

